import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

const CATEGORIES = ['Technology', 'Arts', 'Sports', 'Academic', 'Cultural', 'Business', 'Science', 'Social', 'Other'];

// Strip emoji prefix from categories saved before the value={c} fix
const normalizeCategory = (cat) => {
  if (!cat) return 'Technology';
  if (CATEGORIES.includes(cat)) return cat;
  return CATEGORIES.find(c => cat.includes(c)) || 'Technology';
};

const EMPTY_FORM = {
  title: '', description: '', category: 'Technology', startDate: '', endDate: '',
  venue: '', isVirtual: false, virtualLink: '', maxParticipants: '',
  allowExternal: false, tags: '', coverImage: '',
};

export default function CommunityAdminEvents() {
  const [events, setEvents] = useState([]);
  const [community, setCommunity] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingEvent, setEditingEvent] = useState(null);
  const [form, setForm] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [participants, setParticipants] = useState([]);
  const [statusFilter, setStatusFilter] = useState('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const [evRes, comRes] = await Promise.all([
        api.get('/events/my-community'),
        api.get('/communities/my/profile'),
      ]);
      setEvents(evRes.data.data || []);
      setCommunity(comRes.data.data);
    } catch { toast.error('Failed to load events'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const openCreate = () => { setEditingEvent(null); setForm(EMPTY_FORM); setShowModal(true); };
  const openEdit = (ev) => {
    setEditingEvent(ev);
    setForm({
      title: ev.title, description: ev.description, category: normalizeCategory(ev.category),
      startDate: ev.startDate?.split('T')[0], endDate: ev.endDate?.split('T')[0] || '',
      venue: ev.venue || '', isVirtual: ev.isVirtual, virtualLink: ev.virtualLink || '',
      maxParticipants: ev.maxParticipants || '', allowExternal: ev.allowExternal,
      tags: ev.tags?.join(', ') || '', coverImage: ev.coverImage || '',
    });
    setShowModal(true);
  };

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        tags: form.tags ? form.tags.split(',').map(t => t.trim()).filter(Boolean) : [],
        maxParticipants: form.maxParticipants ? parseInt(form.maxParticipants) : undefined,
      };
      if (editingEvent) {
        await api.put(`/events/${editingEvent._id}`, payload);
        toast.success('Event updated!');
      } else {
        await api.post('/events', payload);
        toast.success('Event created!');
      }
      setShowModal(false);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save event');
    } finally {
      setSaving(false);
    }
  };

  const updateStatus = async (id, status) => {
    try {
      await api.put(`/events/${id}/status`, { status });
      toast.success(`Event ${status}!`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update status');
    }
  };

  const deleteEvent = async (id, title) => {
    if (!window.confirm(`Delete "${title}"?`)) return;
    try {
      await api.delete(`/events/${id}`);
      toast.success('Event deleted');
      fetchData();
    } catch { toast.error('Failed'); }
  };

  const viewParticipants = async (ev) => {
    setSelectedEvent(ev);
    try {
      const res = await api.get(`/events/${ev._id}/participants`);
      setParticipants(res.data.data || []);
    } catch { setParticipants([]); }
  };

  const filteredEvents = statusFilter ? events.filter(e => e.status === statusFilter) : events;

  const getCategoryIcon = (category) => {
    const icons = {
      Technology: '💻',
      Arts: '🎨',
      Sports: '⚽',
      Academic: '📚',
      Cultural: '🎭',
      Business: '💼',
      Science: '🔬',
      Social: '🤝',
      Other: '🌟'
    };
    return icons[category] || '📅';
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'published': return '#10b981';
      case 'draft': return 'var(--warning)';
      case 'completed': return 'var(--purple-light)';
      case 'cancelled': return '#ef4444';
      default: return 'var(--text-muted)';
    }
  };

  if (loading) return (
    <div className="loading-screen" style={{ 
      minHeight: '400px',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '16px'
    }}>
      <div className="spinner" style={{ width: '40px', height: '40px', borderWidth: '3px' }} />
      <span style={{ color: 'var(--text-secondary)' }}>Loading events...</span>
    </div>
  );

  return (
    <div className="page-wrapper" style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: 1200, margin: '0 auto', padding: '32px 20px' }}>

        {/* Enhanced Header */}
        <div className="page-header" style={{ marginBottom: 32 }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'flex-start',
            flexWrap: 'wrap',
            gap: '16px'
          }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                <div style={{ 
                  width: '48px', 
                  height: '48px', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '24px'
                }}>
                  📅
                </div>
                <div>
                  <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                    EVENT <span className="gradient-text">MANAGEMENT</span>
                  </h2>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '4px' }}>
                    {community?.name} — Create and manage community events
                  </p>
                </div>
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <Link to="/community-admin" className="btn btn-outline" style={{ 
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span>←</span> Dashboard
              </Link>
              <button onClick={openCreate} className="btn btn-primary" style={{ 
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span>+</span> New Event
              </button>
            </div>
          </div>
        </div>

        {/* Enhanced Status Filter */}
        <div style={{ 
          display: 'flex', 
          gap: '12px', 
          marginBottom: '32px',
          flexWrap: 'wrap',
          padding: '4px',
          background: 'var(--bg-elevated)',
          borderRadius: 'var(--radius-md)',
          border: '1px solid rgba(255,255,255,0.05)'
        }}>
          {[
            { value: '', label: 'All Events', icon: '📊', color: 'var(--purple-light)' },
            { value: 'draft', label: 'Drafts', icon: '📝', color: 'var(--warning)' },
            { value: 'published', label: 'Published', icon: '🚀', color: '#10b981' },
            { value: 'completed', label: 'Completed', icon: '✅', color: 'var(--purple-light)' },
            { value: 'cancelled', label: 'Cancelled', icon: '❌', color: '#ef4444' }
          ].map((filter) => (
            <button 
              key={filter.value} 
              onClick={() => setStatusFilter(filter.value)} 
              style={{
                flex: 1,
                padding: '10px 16px',
                background: statusFilter === filter.value ? filter.color : 'transparent',
                color: statusFilter === filter.value ? 'white' : 'var(--text-secondary)',
                border: 'none',
                borderRadius: 'var(--radius-sm)',
                cursor: 'pointer',
                fontSize: '0.85rem',
                fontWeight: statusFilter === filter.value ? '600' : '400',
                transition: 'all 0.2s',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '8px'
              }}
            >
              <span>{filter.icon}</span> {filter.label}
              {filter.value && (
                <span style={{ 
                  background: statusFilter === filter.value ? 'rgba(255,255,255,0.2)' : 'rgba(255,255,255,0.1)',
                  padding: '2px 6px',
                  borderRadius: '100px',
                  fontSize: '0.7rem'
                }}>
                  {events.filter(e => e.status === filter.value).length}
                </span>
              )}
            </button>
          ))}
        </div>

        {filteredEvents.length === 0 ? (
          <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
            <div style={{ fontSize: '4rem', marginBottom: '16px' }}>📅</div>
            <div style={{ fontSize: '1.1rem', marginBottom: '8px' }}>No events found</div>
            <div style={{ color: 'var(--text-muted)', marginBottom: '24px' }}>
              {statusFilter ? `No ${statusFilter} events` : 'Create your first community event'}
            </div>
            <button onClick={openCreate} className="btn btn-primary" style={{ 
              display: 'inline-flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>+</span> Create First Event
            </button>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {filteredEvents.map(ev => (
              <div key={ev._id} className="card" style={{ 
                padding: '20px',
                transition: 'transform 0.2s, box-shadow 0.2s',
                borderLeft: `4px solid ${getStatusColor(ev.status)}`
              }}>
                <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px', flexWrap: 'wrap' }}>
                  {/* Event Icon */}
                  <div style={{ 
                    width: '48px', 
                    height: '48px', 
                    background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                    borderRadius: 'var(--radius-md)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '1.5rem'
                  }}>
                    {getCategoryIcon(ev.category)}
                  </div>

                  {/* Event Details */}
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '12px', flexWrap: 'wrap' }}>
                      <h4 style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', margin: 0 }}>
                        {ev.title}
                      </h4>
                      <span className={`badge badge-${ev.status}`} style={{ 
                        background: `linear-gradient(135deg, ${getStatusColor(ev.status)}, ${getStatusColor(ev.status)}cc)`,
                        display: 'flex',
                        alignItems: 'center',
                        gap: '4px'
                      }}>
                        {ev.status === 'published' ? '✓' : ev.status === 'draft' ? '📝' : ev.status === 'completed' ? '✅' : '❌'} {ev.status}
                      </span>
                      <span className={`badge badge-${ev.category?.toLowerCase()}`} style={{ 
                        background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '4px'
                      }}>
                        {getCategoryIcon(ev.category)} {ev.category}
                      </span>
                      {ev.allowExternal && ev.eventCode && (
                        <span style={{ 
                          background: 'rgba(16,185,129,0.15)', 
                          color: '#10b981', 
                          border: '1px solid rgba(16,185,129,0.3)', 
                          borderRadius: '100px', 
                          padding: '4px 12px', 
                          fontSize: '0.7rem', 
                          fontFamily: 'var(--font-mono)',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '4px'
                        }}>
                          🔑 CODE: {ev.eventCode}
                        </span>
                      )}
                    </div>

                    <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '12px', lineHeight: '1.5' }}>
                      {ev.description?.substring(0, 150)}...
                    </p>

                    <div style={{ display: 'flex', gap: '24px', fontSize: '0.78rem', color: 'var(--text-muted)', flexWrap: 'wrap' }}>
                      <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                        📅 {new Date(ev.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                      </span>
                      {ev.venue && (
                        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                          📍 {ev.venue}
                        </span>
                      )}
                      {ev.isVirtual && (
                        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                          💻 Virtual
                        </span>
                      )}
                      <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                        👥 {ev.participants?.length || 0} / {ev.maxParticipants || '∞'} registered
                      </span>
                      {ev.maxParticipants && ev.participants?.length > 0 && (
                        <div style={{ width: '100px' }}>
                          <div style={{ 
                            height: '4px', 
                            background: 'var(--bg-elevated)', 
                            borderRadius: '2px',
                            overflow: 'hidden'
                          }}>
                            <div style={{ 
                              width: `${(ev.participants?.length / ev.maxParticipants) * 100}%`, 
                              height: '100%', 
                              background: 'linear-gradient(90deg, var(--purple-primary), var(--cyan-accent))'
                            }} />
                          </div>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Actions */}
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', alignItems: 'flex-end' }}>
                    <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                      {ev.status === 'draft' && (
                        <button 
                          onClick={() => updateStatus(ev._id, 'published')} 
                          className="btn btn-sm" 
                          style={{ 
                            background: 'linear-gradient(135deg, #10b981, #059669)',
                            border: 'none',
                            color: 'white'
                          }}
                        >
                          🚀 Publish
                        </button>
                      )}
                      {ev.status === 'published' && (
                        <>
                          <button 
                            onClick={() => updateStatus(ev._id, 'completed')} 
                            className="btn btn-success btn-sm"
                            style={{ background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))' }}
                          >
                            ✅ Complete
                          </button>
                          <button 
                            onClick={() => updateStatus(ev._id, 'draft')} 
                            className="btn btn-outline btn-sm"
                          >
                            📝 Unpublish
                          </button>
                        </>
                      )}
                      {ev.status === 'cancelled' && (
                        <button 
                          onClick={() => updateStatus(ev._id, 'draft')} 
                          className="btn btn-outline btn-sm"
                        >
                          🔄 Restore to Draft
                        </button>
                      )}
                      {(ev.status === 'draft' || ev.status === 'published') && (
                        <button 
                          onClick={() => updateStatus(ev._id, 'cancelled')} 
                          className="btn btn-danger btn-sm"
                          style={{ background: 'linear-gradient(135deg, #ef4444, #dc2626)' }}
                        >
                          ❌ Cancel
                        </button>
                      )}
                    </div>
                    <div style={{ display: 'flex', gap: '6px' }}>
                      <button 
                        onClick={() => viewParticipants(ev)} 
                        className="btn btn-outline btn-sm"
                        style={{ display: 'flex', alignItems: 'center', gap: '4px' }}
                      >
                        👥 Participants ({ev.participants?.length || 0})
                      </button>
                      <button 
                        onClick={() => openEdit(ev)} 
                        className="btn btn-outline btn-sm"
                        style={{ display: 'flex', alignItems: 'center', gap: '4px' }}
                      >
                        ✏️ Edit
                      </button>
                      <button 
                        onClick={() => deleteEvent(ev._id, ev.title)} 
                        className="btn btn-sm" 
                        style={{ 
                          background: 'rgba(239,68,68,0.1)', 
                          border: '1px solid rgba(239,68,68,0.3)', 
                          color: 'var(--danger)',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '4px'
                        }}
                      >
                        🗑 Delete
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Enhanced Event Form Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowModal(false)} style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(0,0,0,0.8)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000
        }}>
          <div className="modal" style={{ 
            maxWidth: 680, 
            width: '90%',
            maxHeight: '90vh',
            overflowY: 'auto',
            background: 'var(--bg-secondary)',
            borderRadius: 'var(--radius-lg)',
            padding: '32px',
            border: '1px solid rgba(255,255,255,0.1)'
          }}>
            <div style={{ marginBottom: '24px' }}>
              <h3 className="modal-title" style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', marginBottom: '8px' }}>
                {editingEvent ? '✏️ EDIT EVENT' : '➕ CREATE EVENT'}
              </h3>
              <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>
                {editingEvent ? 'Update event details and settings' : 'Create a new event for your community (starts as Draft)'}
              </p>
            </div>

            <form onSubmit={handleSave}>
              <div className="form-group" style={{ marginBottom: '20px' }}>
                <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                  <span>📝</span> Title *
                </label>
                <input 
                  className="form-control" 
                  value={form.title} 
                  onChange={e => set('title', e.target.value)} 
                  placeholder="Enter event title"
                  required 
                  style={{ padding: '12px' }}
                />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '20px' }}>
                <div className="form-group">
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span>📂</span> Category
                  </label>
                  <select 
                    className="form-control" 
                    value={form.category} 
                    onChange={e => set('category', e.target.value)}
                    style={{ padding: '12px' }}
                  >
                    {CATEGORIES.map(c => (
                      <option key={c} value={c}>{getCategoryIcon(c)} {c}</option>
                    ))}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span>📅</span> Start Date *
                  </label>
                  <input 
                    className="form-control" 
                    type="date" 
                    value={form.startDate} 
                    onChange={e => set('startDate', e.target.value)} 
                    required 
                    style={{ padding: '12px' }}
                  />
                </div>
              </div>

              <div className="form-group" style={{ marginBottom: '20px' }}>
                <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                  <span>📖</span> Description *
                </label>
                <textarea 
                  className="form-control" 
                  rows={4} 
                  value={form.description} 
                  onChange={e => set('description', e.target.value)} 
                  placeholder="Describe your event in detail..."
                  required 
                  style={{ 
                    resize: 'vertical', 
                    padding: '12px',
                    lineHeight: '1.6'
                  }}
                />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '20px' }}>
                <div className="form-group">
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span>📍</span> Venue
                  </label>
                  <input 
                    className="form-control" 
                    value={form.venue} 
                    onChange={e => set('venue', e.target.value)} 
                    placeholder="Physical location"
                    style={{ padding: '12px' }}
                  />
                </div>
                <div className="form-group">
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span>👥</span> Max Participants
                  </label>
                  <input 
                    className="form-control" 
                    type="number" 
                    value={form.maxParticipants} 
                    onChange={e => set('maxParticipants', e.target.value)} 
                    placeholder="Unlimited if empty"
                    style={{ padding: '12px' }}
                  />
                </div>
              </div>

              <div style={{ display: 'flex', gap: '24px', marginBottom: '20px', padding: '12px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)' }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  <input type="checkbox" checked={form.isVirtual} onChange={e => set('isVirtual', e.target.checked)} />
                  💻 Virtual Event
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  <input type="checkbox" checked={form.allowExternal} onChange={e => set('allowExternal', e.target.checked)} />
                  🌐 Allow External Participants (generates join code)
                </label>
              </div>

              {form.isVirtual && (
                <div className="form-group" style={{ marginBottom: '20px' }}>
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span>🔗</span> Virtual Link
                  </label>
                  <input 
                    className="form-control" 
                    value={form.virtualLink} 
                    onChange={e => set('virtualLink', e.target.value)} 
                    placeholder="https://meet.google.com/..."
                    style={{ padding: '12px' }}
                  />
                </div>
              )}

              <div className="form-group" style={{ marginBottom: '24px' }}>
                <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                  <span>🏷️</span> Tags (comma-separated)
                </label>
                <input 
                  className="form-control" 
                  value={form.tags} 
                  onChange={e => set('tags', e.target.value)} 
                  placeholder="tech, workshop, networking"
                  style={{ padding: '12px' }}
                />
              </div>

              <div style={{ display: 'flex', gap: '12px', justifyContent: 'flex-end', marginTop: '24px' }}>
                <button type="button" onClick={() => setShowModal(false)} className="btn btn-outline" style={{ padding: '10px 24px' }}>
                  Cancel
                </button>
                <button type="submit" className="btn btn-primary" disabled={saving} style={{ 
                  padding: '10px 24px',
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  {saving ? (
                    <>
                      <span className="spinner" style={{ width: '16px', height: '16px', borderWidth: '2px' }} />
                      Saving...
                    </>
                  ) : (
                    <>
                      {editingEvent ? '💾 Update Event' : '✨ Create Event'}
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Enhanced Participants Modal */}
      {selectedEvent && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setSelectedEvent(null)} style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(0,0,0,0.8)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000
        }}>
          <div className="modal" style={{ 
            maxWidth: 500, 
            width: '90%',
            maxHeight: '80vh',
            overflowY: 'auto',
            background: 'var(--bg-secondary)',
            borderRadius: 'var(--radius-lg)',
            padding: '32px'
          }}>
            <div className="flex-between" style={{ marginBottom: '20px', alignItems: 'center' }}>
              <div>
                <h3 className="modal-title" style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', margin: 0 }}>
                  👥 PARTICIPANTS
                </h3>
                <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginTop: '4px' }}>
                  {selectedEvent.title}
                </p>
              </div>
              <button 
                onClick={() => setSelectedEvent(null)} 
                style={{ 
                  background: 'none', 
                  border: 'none', 
                  color: 'var(--text-muted)', 
                  cursor: 'pointer', 
                  fontSize: '1.5rem',
                  padding: '4px 8px',
                  borderRadius: 'var(--radius-sm)',
                  transition: 'background 0.2s'
                }}
                onMouseEnter={(e) => e.target.style.background = 'rgba(255,255,255,0.1)'}
                onMouseLeave={(e) => e.target.style.background = 'none'}
              >
                ✕
              </button>
            </div>

            <div style={{ 
              marginBottom: '20px',
              padding: '12px',
              background: 'var(--bg-elevated)',
              borderRadius: 'var(--radius-sm)',
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center'
            }}>
              <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>Total Registered</span>
              <span style={{ fontSize: '1.2rem', fontWeight: 'bold', color: 'var(--purple-light)' }}>
                {participants.length}
              </span>
            </div>

            {participants.length === 0 ? (
              <div className="empty-state" style={{ textAlign: 'center', padding: '48px 24px' }}>
                <div style={{ fontSize: '3rem', marginBottom: '12px' }}>👥</div>
                <div style={{ color: 'var(--text-secondary)' }}>No participants yet</div>
                <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginTop: '8px' }}>
                  Be the first to promote this event!
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                {participants.map((p, i) => (
                  <div key={i} style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: '12px', 
                    padding: '12px', 
                    background: 'var(--bg-elevated)', 
                    borderRadius: 'var(--radius-sm)',
                    transition: 'transform 0.2s'
                  }}>
                    <div className="avatar" style={{ 
                      width: '36px', 
                      height: '36px', 
                      background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                      fontSize: '0.9rem'
                    }}>
                      {(p.user?.name || p.externalName)?.charAt(0)}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: '0.85rem', fontWeight: 600, marginBottom: '2px' }}>
                        {p.user?.name || p.externalName}
                      </div>
                      <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>
                        {p.user?.email || p.externalEmail}
                      </div>
                    </div>
                    <span className={`badge badge-${p.type}`} style={{ 
                      background: p.type === 'member' ? 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))' :
                                 p.type === 'external' ? 'linear-gradient(135deg, var(--cyan-accent), var(--purple-primary))' :
                                 'linear-gradient(135deg, #10b981, #059669)'
                    }}>
                      {p.type === 'member' ? '👤 Member' : p.type === 'external' ? '🌐 External' : '👑 Organizer'}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
